}

// This one endpoint drives the whole booking state machine -- swap the
// "status" value depending on where the booking currently is:
//
//   current REQUESTED   -> "ACCEPTED" or "DECLINED"
//   current PAID         -> "IN_PROGRESS"
//   current IN_PROGRESS  -> "COMPLETED"
//
// Any other transition (e.g. REQUESTED straight to COMPLETED) is rejected
// with a 400 that names exactly which transitions ARE legal right now.
